function CommentsSection() {
  const [name, setName] = useState(null);
  const [text, setText] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [toast, setToast] = useState("");

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(""), 3000); };

  const loadMessages = async () => {
    setLoading(true);
    try {
      const result = await window.storage.get(SHARED_KEY, true);
      setMessages(result ? JSON.parse(result.value) : []);
    } catch { setMessages([]); }
    setLoading(false);
  };

  useEffect(() => { loadMessages(); }, []);

  const submit = async () => {
    if (!text.trim() || !name || saving) return;
    setSaving(true);
    const updated = [{ text: text.trim(), author: name, ts: Date.now() }, ...messages];
    try {
      await window.storage.set(SHARED_KEY, JSON.stringify(updated), true);
      setMessages(updated); setText("");
      showToast(name === "Her" ? "Her words are saved 💚" : "Your words are saved 💛");
    } catch { showToast("Couldn't save — try again 🍃"); }
    setSaving(false);
  };

  return (
    <div className="comments-bg">
      <div className="comments-inner">
        <p className="section-label" style={{ textAlign: "center" }}>Just for the two of you</p>
        <h2 style={{ textAlign: "center" }}>Leave something here 🍃</h2>
        <p style={{ textAlign: "center", maxWidth: 520, margin: "0 auto 32px" }}>
          This space belongs to both of you. Every message is shared — you'll both see everything written here.
        </p>
        <div className="name-select">
          <button className={`name-btn ${name === "Him" ? "active" : ""}`} onClick={() => setName("Him")}>Azeez is writing 💛</button>
          <button className={`name-btn ${name === "Her" ? "active" : ""}`} onClick={() => setName("Her")}>She's writing 🍃</button>
        </div>
        {name && (
          <div className="comment-box">
            <textarea value={text} onChange={e => setText(e.target.value.slice(0, 500))}
              onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); submit(); } }}
              placeholder={name === "Her" ? "Dara k rakhna padta hai... or anything on your mind 💚" : "Write something for her to find, Azeez 💛"}
              rows={5} />
            <div className="comment-actions">
              <span className="char-count">{text.length} / 500</span>
              <button className="submit-btn" onClick={submit} disabled={saving || !text.trim()}>{saving ? "Saving..." : "Leave your words ✦"}</button>
            </div>
          </div>
        )}
        <button className="refresh-btn" onClick={loadMessages}>↻ refresh to see new messages</button>
        {loading ? <p className="no-comments">Loading your words...</p>
          : messages.length === 0 ? <p className="no-comments">No words yet... the page is waiting 🍃</p>
          : messages.map((m, i) => (
            <div className={`comment-entry ${m.author === "Her" ? "her" : "him"}`} key={i}>
              <div className="comment-meta">
                <span className={`comment-author ${m.author === "Her" ? "her" : "him"}`}>{m.author === "Her" ? "Hana 🍃" : "Azeez 💛"}</span>
                <span className="comment-time">{formatTime(m.ts)}</span>
              </div>
              <div className="comment-text">{m.text}</div>
            </div>
          ))}
      </div>
      <div className={`toast ${toast ? "show" : ""}`}>{toast}</div>
    </div>
  );
}

